"""Tests for bolyra.envelope — mirrors TS SDK test cases."""

import json
from pathlib import Path

import pytest
from pydantic import ValidationError

from bolyra.envelope import (
    CONTENT_TYPE,
    ENVELOPE_VERSION,
    ProofEnvelope,
    envelope_from_snarkjs_proof,
)

# Golden fixture generated by the TS SDK
FIXTURE_PATH = (
    Path(__file__).resolve().parents[2]
    / ".."
    / "sdk"
    / "test"
    / "fixtures"
    / "envelope_v1.json"
)


def _load_fixture() -> dict:
    return json.loads(FIXTURE_PATH.read_text())


class TestContentType:
    def test_value(self):
        assert CONTENT_TYPE == "application/bolyra-proof+json"


class TestRoundTrip:
    def test_serialize_deserialize(self):
        data = _load_fixture()
        envelope = ProofEnvelope.model_validate(data)
        json_str = envelope.to_json()
        restored = ProofEnvelope.from_json(json_str)
        assert restored.version == envelope.version
        assert restored.circuit == envelope.circuit
        assert restored.publicSignals == envelope.publicSignals
        assert restored.proof.protocol == envelope.proof.protocol


class TestVersionValidation:
    def test_reject_unknown_major(self):
        data = _load_fixture()
        data["version"] = "2.0"
        with pytest.raises(ValueError, match="Unsupported envelope major version 2"):
            ProofEnvelope.from_json(json.dumps(data))

    def test_accept_compatible_minor(self):
        data = _load_fixture()
        data["version"] = "1.1"
        envelope = ProofEnvelope.from_json(json.dumps(data))
        assert envelope.version == "1.1"


class TestMissingFields:
    def test_missing_circuit(self):
        data = _load_fixture()
        del data["circuit"]
        with pytest.raises(ValidationError):
            ProofEnvelope.model_validate(data)

    def test_missing_proof(self):
        data = _load_fixture()
        del data["proof"]
        with pytest.raises(ValidationError):
            ProofEnvelope.model_validate(data)

    def test_empty_circuit(self):
        data = _load_fixture()
        data["circuit"] = ""
        with pytest.raises(ValidationError):
            ProofEnvelope.model_validate(data)


class TestProofFieldErrors:
    def test_invalid_protocol(self):
        data = _load_fixture()
        data["proof"]["protocol"] = "fflonk"
        with pytest.raises(ValidationError):
            ProofEnvelope.model_validate(data)


class TestEnvelopeFromSnarkjs:
    def test_wraps_proof(self):
        proof = {
            "pi_a": ["1", "2", "1"],
            "pi_b": [["3", "4"], ["5", "6"], ["1", "0"]],
            "pi_c": ["7", "8", "1"],
            "protocol": "groth16",
        }
        signals = ["100", "200"]
        envelope = envelope_from_snarkjs_proof("AgentPolicy", proof, signals)
        assert envelope.version == ENVELOPE_VERSION
        assert envelope.circuit == "AgentPolicy"
        assert envelope.publicSignals == signals
        assert envelope.proof.protocol == "groth16"


class TestFixtureInterop:
    def test_parse_ts_fixture(self):
        """Parse the golden fixture generated by the TS SDK."""
        raw = FIXTURE_PATH.read_text()
        envelope = ProofEnvelope.from_json(raw)
        assert envelope.version == "1.0"
        assert envelope.circuit == "HumanUniqueness"
        assert len(envelope.publicSignals) == 3
        assert envelope.proof.protocol == "groth16"
        assert envelope.metadata.prover == "@bolyra/sdk"
